// Delegate to the vision specialist and files dispatcher for all attachments at once.
const [seen, fileAnswer] = await Promise.all([
  delegate('system-vision', 'vision', {
    query: 'Describe the photo of Stone Town, Zanzibar — what do you see? Keep it brief, a couple of sentences capturing the key subject and atmosphere.',
    attachmentIds: ['b889826f-f6ae-47fc-8b62-7168af04a519'],
  }) as string,
  delegate('system-files', 'dispatch', {
    query: 'Summarize these three documents for me — tanzaniamemories.md (notes), trip-costs.xlsx (spreadsheet), ngorongoro-conservation-area-tariffs.pdf (park fees). For each, give a short summary of what it covers, and list the concrete specifics I need to plan around: names, numbers, dates, costs, payment statuses, reference codes. I need enough detail to build an app and to populate per-topic knowledge spaces — but keep it tight.',
    attachmentIds: [
      'ac14d397-2d53-4a4e-9189-ad1e14ac48bd', // tanzaniamemories.md
      'e7d6a1ff-456b-4bb7-8e4a-8d9c2b7b9c9f', // trip-costs.xlsx
      '416bcc9f-31ba-4874-b1ec-d1a0ce0daa91', // ngorongoro-conservation-area-tariffs.pdf
    ],
  }) as string,
]);
